part of 'novels_book_cubit.dart';@immutablesealed class NovelsBooksState {}final class NovelsBooksInitial extends NovelsBooksState {}final class NovelsBooksLoading extends NovelsBooksState {}final class NovelsBooksSuccess extends NovelsBooksState {  final List<BookModel> books;  NovelsBooksSuccess({required this.books});}final class NovelsBooksFailure extends NovelsBooksState {  final String error;  NovelsBooksFailure({required this.error});}